import{_ as o,o as i,c as l,av as a}from"./chunks/framework.CPLujixp.js";const p=JSON.parse('{"title":"介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1773320546000}'),t={name:"guide/introduction.md"};function d(c,e,r,n,u,s){return i(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h1><p><code>ssq-ui</code> 是一个基于 <code>Vue 3 + TypeScript</code> 的组件库项目，目标是构建一套既适合业务项目直接接入，也便于持续维护和开源发布的前端组件体系。</p><h2 id="设计目标" tabindex="-1">设计目标 <a class="header-anchor" href="#设计目标" aria-label="Permalink to &quot;设计目标&quot;">​</a></h2><ul><li>提供清晰稳定的组件 API，降低业务接入成本。</li><li>在基础组件之外，补齐弹层、主题、按需加载等关键能力。</li><li>让组件视觉风格、交互行为与工程组织都具备可扩展性。</li></ul><h2 id="当前能力" tabindex="-1">当前能力 <a class="header-anchor" href="#当前能力" aria-label="Permalink to &quot;当前能力&quot;">​</a></h2><ul><li>基础组件：<code>Button</code>、<code>Icon</code>、<code>Input</code>、<code>Space</code></li><li>反馈组件：<code>Dialog</code></li><li>数据录入：<code>Select</code></li><li>数据展示：<code>Table</code></li><li>主题系统：<code>ConfigProvider</code>、<code>useTheme</code></li><li>公共基础设施：overlay registry、focus trap、scroll lock、Teleport 目标解析</li></ul><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><ul><li>构建：<code>Vite</code></li><li>语言与框架：<code>Vue 3</code>、<code>TypeScript</code></li><li>测试：<code>Vitest</code>、<code>@vue/test-utils</code></li><li>文档：<code>VitePress</code></li><li>浮层定位：<code>@floating-ui/vue</code></li></ul><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to &quot;项目亮点&quot;">​</a></h2><ul><li><code>Dialog</code> 和 <code>Select</code> 复用同一套弹层基础设施，避免重复实现滚动锁定、焦点管理和键盘关闭逻辑。</li><li><code>Table</code> 同时覆盖排序、筛选、固定列和虚拟滚动这几类常见数据展示需求，适合直接承载后台列表页。</li><li>支持全量安装与子路径导入，子路径默认自动注入组件样式，便于按需加载。</li><li>主题系统基于全局 <code>--my-*</code> token 工作，运行时切换后能够自动覆盖 Teleport 到 <code>body</code> 的组件。</li></ul><h2 id="推荐阅读" tabindex="-1">推荐阅读 <a class="header-anchor" href="#推荐阅读" aria-label="Permalink to &quot;推荐阅读&quot;">​</a></h2><ul><li>如果你准备先浏览整体能力，建议先看 <a href="/ssq-ui/guide/getting-started.html">快速开始</a>。</li><li>如果你要搭建列表页或数据展示页，可以直接跳转到 <a href="/ssq-ui/components/table.html">Table 表格</a>。</li><li>如果你想先确认主题定制能力，可继续查看 <a href="/ssq-ui/guide/theme-lab.html">主题编辑器</a>。</li></ul>',12)])])}const m=o(t,[["render",d]]);export{p as __pageData,m as default};
